package com.example.demo.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Arrays;
import java.util.UUID;

@RestController
@RequestMapping("/api/profile")
public class ProfilePictureController {

    @Value("${upload.directory}")
    private String uploadDirectory;

    @Value("${upload.max-size}")
    private long maxSize;

    private static final String[] ALLOWED_EXTENSIONS = {"jpg", "jpeg", "png", "gif", "webp"};
    private static final String[] ALLOWED_MIME_TYPES = {"image/jpeg", "image/png", "image/gif", "image/webp"};

    @PostMapping("/upload")
    public ResponseEntity<?> uploadProfilePicture(@RequestParam("file") MultipartFile file) {
        try {
            if (file.isEmpty()) {
                return ResponseEntity.badRequest().body("File is empty");
            }

            if (file.getSize() > maxSize) {
                return ResponseEntity.badRequest().body("File size exceeds limit");
            }

            String originalFileName = file.getOriginalFilename();
            if (originalFileName == null || !isValidFileExtension(originalFileName)) {
                return ResponseEntity.badRequest().body("Invalid file type");
            }

            if (!isValidMimeType(file)) {
                return ResponseEntity.badRequest().body("Invalid file content");
            }

            BufferedImage image = ImageIO.read(file.getInputStream());
            if (image == null) {
                return ResponseEntity.badRequest().body("Invalid image file");
            }

            String serverFileName = UUID.randomUUID().toString() + "_" + System.currentTimeMillis();
            String fileExtension = getFileExtension(originalFileName);
            String storagePath = uploadDirectory + File.separator + serverFileName + "." + fileExtension;

            Path path = Paths.get(storagePath);
            Files.createDirectories(path.getParent());
            file.transferTo(path.toFile());

            String fileUrl = "/uploads/" + serverFileName + "." + fileExtension;
            return ResponseEntity.ok().body(new FileUploadResponse(fileUrl));

        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("Upload failed");
        }
    }

    private boolean isValidFileExtension(String fileName) {
        String extension = getFileExtension(fileName).toLowerCase();
        return Arrays.asList(ALLOWED_EXTENSIONS).contains(extension);
    }

    private boolean isValidMimeType(MultipartFile file) {
        String contentType = file.getContentType();
        if (contentType == null) {
            return false;
        }
        return Arrays.asList(ALLOWED_MIME_TYPES).contains(contentType);
    }

    private String getFileExtension(String fileName) {
        int lastDotIndex = fileName.lastIndexOf('.');
        if (lastDotIndex > 0) {
            return fileName.substring(lastDotIndex + 1);
        }
        return "";
    }

    private static class FileUploadResponse {
        private final String url;

        public FileUploadResponse(String url) {
            this.url = url;
        }

        public String getUrl() {
            return url;
        }
    }
}